355     }
356 
357     Known = analyzeKnownBitsFromAndXorOr(cast<Operator>(I), LHSKnown, RHSKnown,
358                                          Q, Depth);
359 
360     // If the client is only demanding bits that we know, return the known
361     // constant.
362     if (DemandedMask.isSubsetOf(Known.Zero | Known.One))
